        "id": "michigan-medicare-assistance-program",
        "name": "Michigan Medicare Assistance Program (MMAP)",
        "shortName": "Medicare Counseling",
        "tagline": "Free one-on-one help navigating Medicare, Medicaid, and prescription drug coverage for your parent.",
        "programType": "benefit",
